+      addStyle([['./style-30.css', '.foo { color: red }', '']], {
+        insertInto: '#test><><><',
+      })
+    ).toThrowErrorMatchingSnapshot();
+  });
+
+  it('should throw error with invalid "insertAt" option', () => {
+    expect(() =>
+      addStyle([['./style-31.css', '.foo { color: red }', '']], {
+        insertAt: 'invalid',
+      })
+    ).toThrowErrorMatchingSnapshot();
+  });
