diff --git a/test/singleton-option.test.js b/test/singleton-option.test.js
new file mode 100644
index 0000000..fd0d694
--- /dev/null
+++ b/test/singleton-option.test.js
@@ -0,0 +1,58 @@
+import compile from './helpers/compiler';
+import runTestInJsdom from './helpers/runTestInJsdom';
+
+describe('singleton option', () => {
+  it('not specified', async () => {
+    expect.assertions(3);
+
+    const testId = './singleton.js';
+    const stats = await compile(testId);
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+
+  it('false', async () => {
+    expect.assertions(3);
+
+    const testId = './singleton.js';
+    const stats = await compile(testId, {
+      loader: {
+        options: {
+          singleton: false,
+        },
+      },
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+
+  it('true', async () => {
+    expect.assertions(3);
+
+    const testId = './singleton.js';
+    const stats = await compile(testId, {
+      loader: {
+        options: {
+          singleton: true,
+        },
+      },
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+});

diff --git a/test/sourceMap-option.test.js b/test/sourceMap-option.test.js
new file mode 100644
index 0000000..4fb6710
--- /dev/null
+++ b/test/sourceMap-option.test.js
@@ -0,0 +1,93 @@
+import compile from './helpers/compiler';
+import runTestInJsdom from './helpers/runTestInJsdom';
+
+describe('sourceMap option', () => {
+  it('not specified', async () => {
+    expect.assertions(3);
+
+    const testId = './simple.js';
+    const stats = await compile(testId, {
+      devtool: 'source-map',
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+
+  it('false', async () => {
+    expect.assertions(3);
+
+    const testId = './simple.js';
+    const stats = await compile(testId, {
+      devtool: 'source-map',
+      loader: {
+        options: {
+          sourceMap: false,
+        },
+      },
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+
+  it('true', async () => {
+    expect.assertions(3);
+
+    const testId = './simple.js';
+    const stats = await compile(testId, {
+      devtool: 'source-map',
+      loader: {
+        options: {
+          sourceMap: true,
+        },
+      },
+      cssLoader: {
+        options: {
+          sourceMap: true,
+        },
+      },
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+
+  it('true, but previous loader do not generate source map', async () => {
+    expect.assertions(3);
+
+    const testId = './simple.js';
+    const stats = await compile(testId, {
+      devtool: 'source-map',
+      loader: {
+        options: {
+          sourceMap: true,
+        },
+      },
+      cssLoader: {
+        options: {
+          sourceMap: false,
+        },
+      },
+    });
+
+    runTestInJsdom(stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot('DOM');
+    });
+
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
+});

