diff --git a/test/runtime/injectStylesIntoLinkTag.test.js b/test/runtime/injectStylesIntoLinkTag.test.js
new file mode 100644
index 0000000..9418597
--- /dev/null
+++ b/test/runtime/injectStylesIntoLinkTag.test.js
@@ -0,0 +1,36 @@
+/* eslint-env browser */
+
+import injectStylesIntoLinkTag from '../../src/runtime/injectStylesIntoLinkTag';
+
+describe('addStyle', () => {
+  beforeEach(() => {
+    document.head.innerHTML = '<title>Title</title>';
+    document.body.innerHTML = '<h1>Hello world</h1>';
+  });
+
+  // Each query should have be unique because style-loader caching styles in dom
+
+  it('should work', () => {
+    injectStylesIntoLinkTag('./style-1.css');
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "attributes" option', () => {
+    injectStylesIntoLinkTag('./style-1.css', { attributes: { foo: 'bar' } });
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "__webpack_nonce__" variable', () => {
+    // eslint-disable-next-line no-underscore-dangle
+    window.__webpack_nonce__ = 'none';
+
+    injectStylesIntoLinkTag('./style-1.css');
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+
+    // eslint-disable-next-line no-underscore-dangle, no-undefined
+    window.__webpack_nonce__ = undefined;
+  });
+});

diff --git a/test/runtime/injectStylesIntoStyleTag.test.js b/test/runtime/injectStylesIntoStyleTag.test.js
new file mode 100644
index 0000000..57a0536
--- /dev/null
+++ b/test/runtime/injectStylesIntoStyleTag.test.js
@@ -0,0 +1,570 @@
+/* eslint-env browser */
+
+import injectStylesIntoStyleTag from '../../src/runtime/injectStylesIntoStyleTag';
+
+describe('addStyle', () => {
+  beforeEach(() => {
+    document.head.innerHTML = '<title>Title</title>';
+    document.body.innerHTML = '<h1>Hello world</h1>';
+  });
+
+  // Each query should have be unique because style-loader caching styles in dom
+
+  it('should work', () => {
+    injectStylesIntoStyleTag([['./style-1.css', '.foo { color: red }', '']]);
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with media', () => {
+    injectStylesIntoStyleTag([
+      [
+        './style-media.css',
+        '.foo { color: red }',
+        'screen and (min-width:320px)',
+      ],
+    ]);
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work #2', () => {
+    injectStylesIntoStyleTag([
+      ['./style-2-1.css', '.foo { color: red }', ''],
+      ['./style-2-2.css', '.bar { color: blue }', ''],
+    ]);
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "attributes" option', () => {
+    injectStylesIntoStyleTag([['./style-3.css', '.foo { color: red }', '']], {
+      attributes: { foo: 'bar' },
+    });
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "attributes" option #2', () => {
+    injectStylesIntoStyleTag(
+      [
+        ['./style-4-1.css', '.foo { color: red }', ''],
+        ['./style-4-2.css', '.bar { color: blue }', ''],
+      ],
+      {
+        attributes: { foo: 'bar' },
+      }
+    );
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "insertAt" option', () => {
+    injectStylesIntoStyleTag(
+      [
+        ['./style-5-1.css', '.foo { color: red }', ''],
+        ['./style-5-2.css', '.bar { color: blue }', ''],
+      ],
+      {
+        insertAt: 'top',
+      }
+    );
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "insertAt" option #2', () => {
+    injectStylesIntoStyleTag(
+      [
+        ['./style-6-1.css', '.foo { color: red }', ''],
+        ['./style-6-2.css', '.bar { color: blue }', ''],
+      ],
+      {
+        insertAt: 'bottom',
+      }
+    );
+
+    expect(document.documentElement.innerHTML).toMatchSnapshot();
+  });
+
+  it('should work with "insertAt" option #3', () => {
