diff --git a/test/styleTagTransform-option.test.js b/test/styleTagTransform-option.test.js
new file mode 100644
index 0000000..e082a62
--- /dev/null
+++ b/test/styleTagTransform-option.test.js
@@ -0,0 +1,49 @@
+/* eslint-env browser */
+
+import {
+  compile,
+  getCompiler,
+  getEntryByInjectType,
+  getErrors,
+  getWarnings,
+  runInJsDom,
+} from "./helpers/index";
+
+describe('"styleTagTransform" option', () => {
+  it(`should work when the "styleTagTransform" option is not specify`, async () => {
+    const entry = getEntryByInjectType("simple.js", "styleTag");
+    const compiler = getCompiler(entry, {
+      injectType: "styleTag",
+    });
+    const stats = await compile(compiler);
+
+    runInJsDom("main.bundle.js", compiler, stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot("DOM");
+    });
+
+    expect(getWarnings(stats)).toMatchSnapshot("warnings");
+    expect(getErrors(stats)).toMatchSnapshot("errors");
+  });
+
+  it(`should work when the "styleTagTransform" option is specify`, async () => {
+    const entry = getEntryByInjectType("simple.js", "styleTag");
+    const compiler = getCompiler(entry, {
+      injectType: "styleTag",
+      // eslint-disable-next-line object-shorthand,func-names
+      styleTagTransform: function (css, style) {
+        // eslint-disable-next-line no-param-reassign
+        style.innerHTML = `${css}.modify{}\n`;
+
+        document.head.appendChild(style);
+      },
+    });
+    const stats = await compile(compiler);
+
+    runInJsDom("main.bundle.js", compiler, stats, (dom) => {
+      expect(dom.serialize()).toMatchSnapshot("DOM");
+    });
+
+    expect(getWarnings(stats)).toMatchSnapshot("warnings");
+    expect(getErrors(stats)).toMatchSnapshot("errors");
+  });
+});

